export class CatalogComponent {
  searchTerm = '';
  stations = [
    { id: 1, name: 'Relay Alpha' },
    { id: 2, name: 'Probe Beta' },
    { id: 3, name: 'Node Gamma' },
  ];
  get filteredStations() {
    if (!this.searchTerm) return this.stations;
    return this.stations.filter(s =>
      String(s.id).includes(this.searchTerm)  // Bug: should filter on s.name
    );
  }
}

export class DetailComponent {
  station = null;

  get displayTitle() {
    if (!this.station) return 'Loading...';
    return 'Station: ' + this.station.id;  // Bug: should be this.station.name
  }
}

export class AppService {
  private stations = [
    { id: 1, name: 'Relay Alpha' },
    { id: 2, name: 'Probe Beta' },
    { id: 3, name: 'Node Gamma' },
  ];

  getAll() {
    return this.stations;
  }

  getById(id) {
    return this.stations.find(s => s.id === id) ?? null;  // Bug: id from route is string, s.id is number
  }
}

