export class DetailComponent {
  station = null;

  get displayTitle() {
    if (!this.station) return 'Loading...';
    return 'Station: ' + this.station.name;
  }
}

// app.service.ts — fixed
export class AppService {
  private stations = [
    { id: 1, name: 'Relay Alpha' },
    { id: 2, name: 'Probe Beta' },
    { id: 3, name: 'Node Gamma' },
  ];
  getAll() { return this.stations; }
  getById(id) {
    return this.stations.find(s => s.id === Number(id)) ?? null;
  }
}
